POST https://events.pagerduty.com/v2/enqueue
Body: {routing_key: integration_key, event_action: 'trigger', payload: {summary, severity, source}, dedup_key: optional}
Severity: critical, error, warning, info
Response: {status: 'success', dedup_key: '...', message: 'Event processed'}
Resolve: event_action='resolve' with same dedup_key

import os
import requests
import logging

log = logging.getLogger(__name__)

EVENTS_URL = 'https://events.pagerduty.com/v2/enqueue'


class PagerDutyService:
    def __init__(self):
        self.routing_key = os.environ.get('PAGERDUTY_ROUTING_KEY', '')

    def trigger_incident(self, summary: str, severity: str = 'critical',
                         source: str = 'monitoring-service', dedup_key: str = None) -> str:
        if not self.routing_key:
            log.warning('PAGERDUTY_ROUTING_KEY not set, skipping')
            return ''
        payload = {
            'routing_key': self.routing_key,
            'event_action': 'trigger',
            'dedup_key': dedup_key,
            'payload': {
                'summary': summary,
                'severity': severity,
                'source': source,
            }
        }
        resp = requests.post(EVENTS_URL, json=payload, timeout=10)
        resp.raise_for_status()
        key = resp.json().get('dedup_key', '')
        log.info('PagerDuty incident triggered: %s', key)
        return key

    def resolve_incident(self, dedup_key: str):
        payload = {
            'routing_key': self.routing_key,
            'event_action': 'resolve',
            'dedup_key': dedup_key,
        }
        requests.post(EVENTS_URL, json=payload, timeout=10)
